    48→    message?: string;
    49→  };
    50→}
    51→
    52→function buildExtractRequestPayload(payload: ExtractRequestDto): ExtractRequestDto {
    53→  return {
    54→    participantId: payload.participantId,
    55→    page: payload.page ?? EXTRACT_CONSTANTS.DEFAULT_PAGE,
    56→    pageSize: payload.pageSize ?? EXTRACT_CONSTANTS.DEFAULT_PAGE_SIZE,
    57→    ...(payload.type ? { type: payload.type } : {}),
    58→  };
    59→}
    60→
    61→export async function getPointsExtractApi(
    62→  payload: ExtractRequestDto,
    63→): Promise<AxiosResponse<PointsExtractApiResponse>> {
    64→  const requestPayload = buildExtractRequestPayload(payload);
    65→
    66→  return api.post<PointsExtractApiResponse>(
