    68→    requestPayload,
    69→  );
    70→}
    71→
    72→export async function getPointsBalanceApi(): Promise<AxiosResponse<PointsBalanceApiResponse>> {
    73→  return api.get<PointsBalanceApiResponse>('fintech/v1/rewardProgram/balance', {});
    74→}
